// 1. Lấy dữ liệu từ Node Parser (Output của AI đã được làm sạch)
const parserOutput = $input.first().json.parsed_json || {};

// 2. Lấy dữ liệu gốc từ Request ban đầu (Node 'Webhook')
let requestData = {};
try {
  requestData = $node['Webhook'].json.body || {};
} catch (e) {
  requestData = {};
}

// 3. Lấy thông tin Context (Danh sách ứng viên đã tìm thấy)
let contextData = {};
try {
  contextData = $('Merge Context').first().json.merged_context || {};
} catch (e) {}

// Chuẩn hóa ID
const chatid = String(requestData.message_id || "").trim();
const employeeId = String(requestData.user_id || "").trim();

// --- XỬ LÝ ANSWER MESSAGE CHO DỄ NHÌN ---
let finalAnswer = "";

// Cách 1: Nếu node trước đã tách dòng thành mảng (enriched_lines) -> Nối lại
if (parserOutput.enriched_lines && Array.isArray(parserOutput.enriched_lines) && parserOutput.enriched_lines.length > 0) {
    finalAnswer = parserOutput.enriched_lines.join('\n');
} 
// Cách 2: Nếu chỉ có chuỗi (enriched_answer)
else {
    finalAnswer = parserOutput.enriched_answer || "";
}

// QUAN TRỌNG: Đảm bảo xuống dòng hiển thị đúng
// Replace \\n (chuỗi ký tự do AI sinh ra) thành \n (ký tự xuống dòng thật)
if (typeof finalAnswer === 'string') {
    finalAnswer = finalAnswer.replace(/\\n/g, '\n').replace(/\\t/g, '\t');
}
// ------------------------------------------

// 4. Tạo Response JSON chuẩn cho Frontend
return [
  {
    json: {
      status: "ok",

      // Thông tin định danh phiên chat
      tenantCode: requestData.tenant_code || "",
      chatid: chatid,
      employeeId: employeeId,
      timestamp: requestData.timestamp || new Date().toISOString(),

      // Câu hỏi và Câu trả lời chính
      question_message: $('Webhook').first().json.body.message || "",

      // Gán biến đã xử lý ở trên vào đây
      answer_message: finalAnswer || "Xin lỗi, hệ thống chưa thể xử lý yêu cầu này.",

      // Câu trả lời tóm tắt
      short_message: parserOutput.short_answer || "",

      // Nguồn dữ liệu
      source: parserOutput.source || "TalentIQ Database",

      // Các cờ nghiệp vụ
      needs_human_review: parserOutput.needs_human_review || false,
      follow_up_question: parserOutput.follow_up_question || null,

      // Metadata bổ sung
      candidate_list: contextData.top_candidates ? contextData.top_candidates.map(c => c.name) : [],

      // Tương thích ngược
      answer_url: [], 
      category: contextData.top_candidates ? contextData.top_candidates.map(c => "Candidate Profile") : [],
      clarify_question: null,
      handoff_note: null
    }
  }
];

// Lấy item từ node Webhook
const data = $node['Webhook'].json;

// Chuẩn hóa khoảng trắng cho chatid và employeeId
const chatid = String(data.body.message_id || "").trim();
const employeeId = String(data.body.user_id || "").trim();

// Tạo response JSON
return [
  {
    json: {
      status: "ok",
      tenantCode: data.body.tenant_code || "",
      chatid,
