// n8n Function node: Robust JSON extractor & parser for TalentIQ CV Assessment
// Input: items[].json.output (string) OR items[].json.message.content
// Output: items[].json.parsed_json (object) aligned with TalentIQ schema

// --- 1. HELPER FUNCTIONS (GIỮ NGUYÊN) ---

function tryJsonParse(text) {
  try { return { ok: true, value: JSON.parse(text), method: 'JSON.parse(raw)' }; }
  catch (e) { return { ok: false, error: e.message }; }
}

function extractFirstObjectBlock(text) {
  const m = text.match(/\{[\s\S]*\}/);
  return m ? m[0] : null;
}

function unescapeCommonEscapes(s){
  return s
    .replace(/\\n/g, '\n')   
    .replace(/\\r/g, '\r')
    .replace(/\\"/g, '"')    
    .replace(/\\'/g, "'")
    .replace(/\\\\/g, '\\'); 
}

function parseRobust(raw) {
  const attempts = [];
  if (raw === null || raw === undefined) {
    attempts.push({ method: 'no-input', ok: false });
    return { parsed: null, attempts };
  }

  if (typeof raw === 'object') {
    return { parsed: raw, attempts };
  }

  const s = String(raw);
  let attempt = tryJsonParse(s);
  if (attempt.ok) return { parsed: attempt.value, attempts };

  try {
    const first = JSON.parse(s);
    if (typeof first === 'object') return { parsed: first, attempts };
    if (typeof first === 'string') {
      const secondAttempt = tryJsonParse(first);
      if (secondAttempt.ok) return { parsed: secondAttempt.value, attempts };
      var candidate = first;
    } else {
      var candidate = s;
    }
  } catch(e) {
    var candidate = s;
  }

  const block = extractFirstObjectBlock(candidate);
  if (block) {
    attempt = tryJsonParse(block);
    if (attempt.ok) return { parsed: attempt.value, attempts };
  }

  const unescaped = unescapeCommonEscapes(candidate);
  if (unescaped !== candidate) {
    attempt = tryJsonParse(unescaped);
    if (attempt.ok) return { parsed: attempt.value, attempts };
    const block2 = extractFirstObjectBlock(unescaped);
    if (block2) {
      attempt = tryJsonParse(block2);
      if (attempt.ok) return { parsed: attempt.value, attempts };
    }
  }

  const cleaned = candidate
    .replace(/\u201c|\u201d/g, '"')
    .replace(/\u2018|\u2019/g, "'")
    .replace(/[\u0000-\u0019]+/g, ''); 
  attempt = tryJsonParse(cleaned);
  if (attempt.ok) return { parsed: attempt.value, attempts };

  return { parsed: null, attempts };
}

// --- 2. MAIN LOGIC (CẬP NHẬT TÁCH DÒNG) ---
const outputs = [];

for (const item of items) {
  const rawCandidates = [];
  if (item.json && item.json.output) rawCandidates.push(item.json.output);
  if (item.json && item.json.message && item.json.message.content) rawCandidates.push(item.json.message.content); 
  if (item.json && item.json.response) rawCandidates.push(item.json.response);
  if (item.json && item.json.text) rawCandidates.push(item.json.text);

  if (rawCandidates.length === 0) rawCandidates.push(JSON.stringify(item.json));

  let finalParsed = null;
  for (const raw of rawCandidates) {
    const { parsed } = parseRobust(raw);
    if (parsed) { finalParsed = parsed; break; }
  }

  if (!finalParsed) {
    finalParsed = {
      "enriched_answer": "Hệ thống gặp lỗi khi xử lý dữ liệu từ AI.",
      "short_answer": "Lỗi hệ thống",
      "source": "",
      "needs_human_review": true,
      "follow_up_question": null,
      "confidence": 0
    };
  }

  // --- LOGIC TÁCH DÒNG (SPLIT LINES) ---
  if (finalParsed.enriched_answer && typeof finalParsed.enriched_answer === 'string') {
      // 1. Chuẩn hóa xuống dòng: chuyển hết \\n thành \n thật
      const normalizedText = finalParsed.enriched_answer
          .replace(/\\n/g, '\n')
          .replace(/\\t/g, '\t');

      // 2. Gán lại chuỗi đã chuẩn hóa vào field gốc (để hiển thị đẹp nếu cần in cả cục)
      finalParsed.enriched_answer = normalizedText;

      // 3. Tách thành mảng (Array) dựa trên dấu xuống dòng
      // Filter(Boolean) để loại bỏ các dòng trống vô nghĩa
      finalParsed.enriched_lines = normalizedText
          .split('\n')
          .map(line => line.trim())
          .filter(line => line.length > 0);
  } else {
      finalParsed.enriched_lines = [];
  }

  outputs.push({
    json: {
      parsed_json: finalParsed
    }
  });
}

return outputs;

const input = items[0].json;

// ---- CONFIG ----
const TOP_K_CANDIDATES = 100;      // Số lượng ứng viên tối đa muốn đưa vào context
const MAX_COMBINED_CHARS = 100000; // Tăng giới hạn lên vì thông tin CV thường dài
// ----------------

/**
 * 1. TRÍCH XUẤT DOCS TỪ OUTPUT QDRANT
 * Xử lý các trường hợp output khác nhau của n8n
 */
function extractDocs(obj) {
  if (!obj) return [];
  // Trường hợp chuẩn của bạn: item.json.result
  if (obj.result && Array.isArray(obj.result)) return obj.result;
  // Trường hợp n8n output array trực tiếp
  if (Array.isArray(obj)) return obj;
  return [];
}

const rawDocs = extractDocs(input);

/**
 * 2. GOM NHÓM THEO ỨNG VIÊN (GROUP BY CANDIDATE_ID)
 * Thay vì dedupe (xóa trùng), ta sẽ merge (gộp) thông tin lại.
 */
const candidatesMap = new Map();

for (const doc of rawDocs) {
  const p = doc.payload || {};

  // Bỏ qua nếu không có ID ứng viên
  const cid = p.candidate_id;
  if (!cid) continue;

  const score = doc.score || p.score || 0;
  const textContent = (p.text || "").trim();

  // Nếu ứng viên chưa có trong map, tạo mới
  if (!candidatesMap.has(cid)) {
    candidatesMap.set(cid, {
      id: cid,
      name: p.candidate_name || "Unknown Candidate",
      email: p.candidate_email || "N/A",
      phone: p.candidate_phone || "N/A",
      link_cv: p.link_cv || "",
      max_score: score, // Điểm cao nhất trong các chunk tìm thấy
      matched_chunks: [textContent], // Lưu danh sách các đoạn text khớp
      matched_types: [p.type || p.key || "general"] // Lưu loại (skill, exp...)
    });
  } else {
    // Nếu ứng viên đã tồn tại, cập nhật thêm thông tin
    const c = candidatesMap.get(cid);

    // Cập nhật điểm max nếu chunk này điểm cao hơn
    if (score > c.max_score) {
      c.max_score = score;
    }

    // Thêm đoạn text khớp vào hồ sơ (tránh trùng lặp nội dung y hệt)
    if (!c.matched_chunks.includes(textContent)) {
      c.matched_chunks.push(textContent);
      c.matched_types.push(p.type || p.key || "general");
    }
  }
}

/**
 * 3. SẮP XẾP & LỌC TOP ỨNG VIÊN
 */
// Chuyển Map thành Array
let candidates = Array.from(candidatesMap.values());

// Sắp xếp giảm dần theo điểm cao nhất (Ai khớp nhất lên đầu)
candidates.sort((a, b) => b.max_score - a.max_score);

// Lấy Top K ứng viên
const topCandidates = candidates.slice(0, TOP_K_CANDIDATES);

/**
 * 4. XÂY DỰNG CONTEXT TEXT CHO AI
 * Format lại thành dạng hồ sơ dễ đọc
 */
let combined_context_text = "";

for (const c of topCandidates) {
  // Header của mỗi ứng viên
  const profileHeader = `\n=== ỨNG VIÊN: ${c.name} (Độ phù hợp: ${(c.max_score * 100).toFixed(1)}%) ===\n` +
                        `- Contact: ${c.email} | ${c.phone}\n` +
                        `- Link CV: ${c.link_cv}\n` +
                        `- Thông tin tìm thấy:\n`;

  // Nội dung chi tiết các chunk khớp
  const chunksText = c.matched_chunks.map((chunk, index) => {
    return `  ${index + 1}. ${chunk}`;
  }).join("\n");

  const fullProfile = profileHeader + chunksText + "\n";

  // Kiểm tra giới hạn ký tự
  if (combined_context_text.length + fullProfile.length > MAX_COMBINED_CHARS) {
    // Nếu sắp tràn context thì dừng lại, nhưng cố gắng thêm nốt ứng viên này nếu còn nhiều chỗ
    if (MAX_COMBINED_CHARS - combined_context_text.length > 500) {
       combined_context_text += fullProfile.slice(0, MAX_COMBINED_CHARS - combined_context_text.length) + "... [Truncated]";
    }
    break;
  }

  combined_context_text += fullProfile;
}

// Nếu không tìm thấy ai
if (topCandidates.length === 0) {
  combined_context_text = "Không tìm thấy ứng viên nào phù hợp với yêu cầu.";
}

/**
 * 5. TẠO OUTPUT
 */
// Lấy câu hỏi từ input (nếu có)
let question = $('format output').first().json.refined_question;

const merged_context = {
  question: question,
  candidate_count: topCandidates.length,
  top_candidates: topCandidates.map(c => ({
    name: c.name,
    score: c.max_score,
    link_cv: c.link_cv,
    matched_info_count: c.matched_chunks.length
  })),
  combined_context_text: combined_context_text,
  created_at: new Date().toISOString()
};

return [
  {
    json: {
      merged_context
    }
  }
];

// n8n Function node - produce only `response` (unescaped + auto double-parse)
const items = $input.all();

/** Try to extract and parse a JSON object from a string. */
function tryParseJsonString(src) {
  if (src === null || src === undefined) return null;
  if (typeof src === 'object') return src; // already parsed
  if (typeof src !== 'string') return null;
  const t = src.trim();

  // direct parse
  try {
    return JSON.parse(t);
  } catch (e) {
    // find first {...} or [...] block
    const m = t.match(/[\{\[][\s\S]*[\}\]]/);
    if (m) {
      try {
        return JSON.parse(m[0]);
      } catch (e2) {
        return null;
      }
    }
    return null;
  }
}

/** Unescape common escape sequences inside strings */
function unescapeStringValue(s) {
  if (typeof s !== 'string') return s;
  if (s.indexOf('\\') === -1) return s;
  let r = s;
  r = r.replace(/\\r\\n/g, '\n'); // escaped CRLF -> newline
  r = r.replace(/\\n/g, '\n');    // escaped newline -> newline
  r = r.replace(/\\t/g, '\t');
  r = r.replace(/\\"/g, '"');
  r = r.replace(/\\\\/g, '\\');
  // trim only trailing whitespace
  return r.replace(/\s+$/u, '');
}

function unescapeRecursively(obj) {
  if (obj === null || obj === undefined) return obj;
  if (typeof obj === 'string') return unescapeStringValue(obj);
  if (Array.isArray(obj)) return obj.map(unescapeRecursively);
  if (typeof obj === 'object') {
    const out = {};
    for (const k of Object.keys(obj)) out[k] = unescapeRecursively(obj[k]);
    return out;
  }
  return obj;
}

/** Extract canonical response from parsed content */
function extractCanonicalResponse(parsed) {
  if (typeof parsed === 'string' || typeof parsed === 'number' || typeof parsed === 'boolean') {
    return { response: parsed, original_key: null };
  }
  if (Array.isArray(parsed)) {
    if (parsed.length === 1) return extractCanonicalResponse(parsed[0]);
    return { response: parsed, original_key: null };
  }
  const keyCandidates = [
    'response','answer','answwer','output','reply','message','text','response_text','output_text',
    'result','body','data','content','completion','choices'
  ];
  const lowerMap = {};
  for (const k of Object.keys(parsed || {})) lowerMap[k.toLowerCase()] = k;

  for (const cand of keyCandidates) {
    if (lowerMap[cand]) {
      const realKey = lowerMap[cand];
      return { response: parsed[realKey], original_key: realKey };
    }
  }

  // OpenAI-like choices
  if (parsed.choices && Array.isArray(parsed.choices) && parsed.choices.length > 0) {
    const first = parsed.choices[0];
    if (first.message && first.message.content) return { response: first.message.content, original_key: 'choices[0].message.content' };
    if (first.text) return { response: first.text, original_key: 'choices[0].text' };
  }

  // fallback: whole object
  return { response: parsed, original_key: null };
}

/** Helper: if a string looks like JSON (starts with { or [), try parse it */
function tryDoubleParseString(s) {
  if (typeof s !== 'string') return s;
  const trimmed = s.trim();
  if (!trimmed) return s;
  if (trimmed[0] === '{' || trimmed[0] === '[') {
    try {
      return JSON.parse(trimmed);
    } catch (e) {
      // maybe it's an escaped JSON inside (contains \\n etc) -> unescape then try
      const un = unescapeStringValue(s);
      try {
        return JSON.parse(un);
      } catch (e2) {
        return s; // keep original string
      }
    }
  }
  return s;
}

const out = items.map(item => {
  // candidate raw fields
  const rawCandidate = item.json && (item.json.output ?? item.json.output_text ?? item.output ?? item.payload ?? item.json.response ?? item.json.answer ?? item.json.text ?? item.json);

  // First try parse rawCandidate (if string)
  let parsed = tryParseJsonString(rawCandidate ?? null);

  // fallback: maybe item.json is already an object
  if (!parsed) parsed = tryParseJsonString(item.json ?? null);

  // if still not parsed and rawCandidate is string, keep rawCandidate as parsed value (string)
  if (!parsed) parsed = rawCandidate ?? null;

  // unescape strings inside parsed structure
  const unescaped = unescapeRecursively(parsed);

  // extract canonical response
  const extracted = extractCanonicalResponse(unescaped);

  // If response is a string that itself contains JSON, try double-parse to object/array
  let responseVal = extracted.response;
  if (typeof responseVal === 'string') {
    // unescape again (safe)
    responseVal = unescapeStringValue(responseVal);
    // try parse if looks like JSON
    const doubleParsed = tryDoubleParseString(responseVal);
    responseVal = doubleParsed;
  }

  return {
    json: {
      response: responseVal
    }
  };
});

return out;

// n8n Function node - Normalize AI agent output to JSON & Sanitize Skills
// Input expected: items with item.json.output (string or object)
// Output: items where item.json is the parsed JSON object with STRICT ARRAYS

const items = $input.all();

// --- HELPER 1: Parse JSON an toàn ---
function tryParseJsonString(s) {
  if (typeof s !== 'string') return null;
  const t = s.trim();
  try {
    return JSON.parse(t);
  } catch (e) {
    // Cố gắng tìm block JSON {...} đầu tiên
    const m = t.match(/\{[\s\S]*\}/);
    if (m) {
      try { return JSON.parse(m[0]); } catch (e2) { return null; }
    }
    return null;
  }
}

// --- HELPER 2: Chuẩn hóa danh sách (Quan trọng cho RAG) ---
// Biến "Skill A, Skill B" -> ["Skill A", "Skill B"]
function normalizeList(input) {
    if (!input) return [];

    // Nếu là chuỗi (VD: "Java, Python, SQL") -> Tách thành mảng
    if (typeof input === 'string') {
        // Tách bằng dấu phẩy (,) hoặc chấm phẩy (;)
        return input.split(/,|;/).map(s => s.trim()).filter(s => s.length > 0);
    }

    // Nếu đã là mảng -> Lọc rác
    if (Array.isArray(input)) {
        return input.map(s => String(s).trim()).filter(s => s.length > 0);
    }

    return [];
}

const out = items.map((item) => {
  // Lấy dữ liệu nguồn từ nhiều trường tiềm năng
  const src = item.json && (
      item.json.parsed_json ?? 
      item.json.output ?? 
      item.json.output_text ?? 
      item.output ?? 
      item.payload
  );

  let parsed = null;

  if (src === undefined || src === null) {
    return {
      json: {
        _normalized: null,
        _error: "no_output_field_found",
        original: item.json ?? item
      }
    };
  }

  // 1. PARSE DỮ LIỆU
  if (typeof src === 'object') {
    parsed = src;
  } else {
    parsed = tryParseJsonString(src);
  }

  if (!parsed) {
    return {
      json: {
        _normalized: null,
        _error: "parse_failed",
        raw: src
      }
    };
  }

  // 2. [QUAN TRỌNG] CHUẨN HÓA DỮ LIỆU CHO RAG
  // Đảm bảo filter_skills luôn là Mảng (Array) để Qdrant Search không bị lỗi
  if (parsed.filter_skills) {
      parsed.filter_skills = normalizeList(parsed.filter_skills);
  } else if (parsed.skills) {
      // Fallback: Nếu AI lỡ đặt tên key là "skills" thay vì "filter_skills"
      parsed.filter_skills = normalizeList(parsed.skills);
  }

  // Chuẩn hóa luôn education nếu có
  if (parsed.filter_education) {
      parsed.filter_education = normalizeList(parsed.filter_education);
  }

  // 3. Trả về kết quả sạch đẹp
  return { json: parsed };
});

return out;

// Lấy item đầu tiên
const item = $input.first();
const json = item ? item.json : {};

// 1. TÌM DỮ LIỆU NGUỒN (Quan trọng)
// Webhook n8n thường để dữ liệu trong json.body.
// Code này ưu tiên tìm trong body, nếu không có mới tìm ở root.
const inputData = json.body || json;

// 2. LẤY CÂU HỎI USER
// Tìm trường "message" hoặc "question_message" hoặc "text"
const userQuestion = inputData.message || inputData.question_message || inputData.text || "";

// 3. XỬ LÝ LỊCH SỬ CHAT (HISTORY)
let historyRaw = inputData.history;

// Fix lỗi: Nếu history bị gửi lên dưới dạng String (chưa parse), thì parse nó ra
if (typeof historyRaw === 'string') {
  try {
    historyRaw = JSON.parse(historyRaw);
  } catch (e) {
    historyRaw = [];
  }
}

// Đảm bảo history luôn là mảng
if (!Array.isArray(historyRaw)) {
  historyRaw = [];
}

// Duyệt qua từng tin nhắn để tạo chuỗi Context
const historyLines = historyRaw.map(item => {
  const role = item.role;    
  const content = item.content || "";

  // Map role
  if (role === 'user') {
    return `user_message: ${content}`;
  } else if (role === 'assistant' || role === 'system') {
    return `system_answer: ${content}`;
  }
  return `${role}: ${content}`;
});

// Nối lại thành chuỗi, bỏ dòng trống
const resultString = historyLines.filter(line => line.trim() !== "").join('\n');

// 4. TRẢ VỀ KẾT QUẢ
return [
  {
    json: {
      result_string: resultString, // Context lịch sử
