={{
  (() => {
    // =====================================================================
    // HELPER FUNCTIONS (GIỮ NGUYÊN)
    // =====================================================================

    // 1. Chuẩn hóa text (Tiếng Việt không dấu)
    function removeAccents(str) {
      if (!str) return "";
      return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").trim();
    }

    // 2. Lấy số năm kinh nghiệm
    function extractYearsFromFilter(str) {
      if (!str) return null;
      const match = str.match(/(\d+([.,]\d+)?)/);
      return match ? parseFloat(match[0].replace(',', '.')) : null;
    }

    // 3. Tạo điều kiện match (Robust: Tìm cả có dấu & không dấu)
    function generateMatchClauses(keyword, fields) {
        const rawKey = keyword.trim();
        const cleanKey = removeAccents(rawKey);
        const conditions = [];

        fields.forEach(field => {
            // Match chính xác
            conditions.push({ "key": field, "match": { "text": rawKey } });
            // Match không dấu (nếu khác)
            if (rawKey !== cleanKey) {
                conditions.push({ "key": field, "match": { "text": cleanKey } });
            }
        });
        return conditions;
    }

    // 4. Xử lý Logic (Flattened: Làm phẳng OR/AND để Qdrant dễ hiểu)
    function processLogicFilter(textArray, fields, targetMustArray) {
        if (!textArray) return;
        const items = Array.isArray(textArray) ? textArray : [textArray];

        items.forEach(item => {
            if (!item || item.length > 50) return;

            // Xử lý "HOẶC" / "OR" -> Gom hết vào 1 mảng Should
            if (item.match(/\s+(?:hoặc|or)\s+/i)) {
                const parts = item.split(/\s+(?:hoặc|or)\s+/i);
                let aggregatedShoulds = [];
                parts.forEach(part => {
                    const clauses = generateMatchClauses(part, fields);
                    aggregatedShoulds.push(...clauses);
                });
                targetMustArray.push({ "should": aggregatedShoulds });
            } 
            // Xử lý "VÀ" / "AND" -> Tách từng cái bắt buộc phải có
            else {
                const parts = item.split(/\s*(?:và|and|,)\s*/i);
                parts.forEach(part => { 
                    if(part.trim()) {
                        const clauses = generateMatchClauses(part, fields);
                        targetMustArray.push({ "should": clauses }); 
                    }
                });
            }
        });
    }

    // =====================================================================
    // MAIN LOGIC
    // =====================================================================

    // 1. Lấy Vector Input
    let vector = $json.query_vector || $json.vector;
    if (!vector || vector.length === 0) { vector = new Array(1536).fill(0); }

    // 2. Lấy dữ liệu từ AI
    let aiJson = {};
    try {
      if ($('message refined') && $('message refined').item) {
          aiJson = $('message refined').item.json.parsed_json || JSON.parse($('message refined').item.json.output);
      }
    } catch (e) { aiJson = {}; }

    let mustConditions = [];

    // [QUAN TRỌNG] ĐỊNH NGHĨA PHẠM VI TÌM KIẾM THỐNG NHẤT (UNIFIED SCOPE)
    // Dùng danh sách này cho cả Skill và Education để không bao giờ sót.
    const unifiedFields = [
        "skills_list", // Nơi chứa kỹ năng cứng
        "school",      // Trường học
        "major",       // Chuyên ngành
        "degree",      // Bằng cấp
        "certificate", // Chứng chỉ
        "role",        // Chức danh
        "text"         // Toàn văn CV
    ];

    // A. LỌC TÊN (Giữ nguyên)
    if (aiJson.filter_candidate_name) {
      const clauses = generateMatchClauses(aiJson.filter_candidate_name, ["candidate_name"]);
      mustConditions.push({ "should": clauses });
    }

    // B. LỌC KINH NGHIỆM (Giữ nguyên logic thông minh)
    if (aiJson.filter_experience) {
        const years = extractYearsFromFilter(aiJson.filter_experience);
        if (years !== null) { 
            mustConditions.push({ "key": "experience_years", "range": { "gte": years } }); 
        } else { 
            // Nếu tìm Role, cũng tìm trong unifiedFields luôn cho chắc
            processLogicFilter([aiJson.filter_experience], unifiedFields, mustConditions); 
        }
    }
    if (aiJson.filter_job_title || aiJson.filter_role) { 
        processLogicFilter([aiJson.filter_job_title || aiJson.filter_role], unifiedFields, mustConditions); 
    }

    // ====================================================
    // C. LỌC KỸ NĂNG (Dùng Unified Fields)
    // ====================================================
    // Dù AI bảo là Skill, ta vẫn tìm trong cả Certificate/School...
    if (aiJson.filter_skills) { 
        processLogicFilter(aiJson.filter_skills, unifiedFields, mustConditions); 
    }

    // ====================================================
    // D. LỌC HỌC VẤN (Dùng Unified Fields)
    // ====================================================
    // Dù AI bảo là Edu, ta vẫn tìm trong cả Skills...
    if (aiJson.filter_education) { 
        const edu = Array.isArray(aiJson.filter_education) ? aiJson.filter_education : [aiJson.filter_education];
        processLogicFilter(edu, unifiedFields, mustConditions); 
    }

    // ====================================================
    // CẤU HÌNH OUTPUT
    // ====================================================

    let smartThreshold = 0; 
    if (mustConditions.length === 0) {
        smartThreshold = 0.78; 
    } else {
        smartThreshold = 0.60; 
    }
    if ($json.score_threshold !== undefined) {
        smartThreshold = $json.score_threshold;
    }

    let baseLimit = 15;
    if (aiJson.filter_candidate_name) baseLimit = 5; 
    else if (mustConditions.length > 0) baseLimit = 100;

    let inputLimit = $json.limit || 0;
    let limit = inputLimit > baseLimit ? inputLimit : baseLimit;

    let body = {
      "vector": $json.query_vector,
      "limit": limit,
      "with_payload": true,
      "score_threshold": smartThreshold, 
      "group_by": "candidate_id", 
      "group_size": 1 
    };

    if (mustConditions.length > 0) {
      body.filter = { "must": mustConditions };
    }

    return JSON.stringify(body);
  })()
}}
